100	// sendReceivePack encodes and POSTs a receive-pack request, then decodes the report.
101	func sendReceivePack(
102		ctx context.Context,
103		conn *Conn,
104		req *packp.UpdateRequests,
105		packData io.Reader,
106		verbose bool,
107	) error {
108		var header bytes.Buffer
109		if err := req.Encode(&header); err != nil {
110			return fmt.Errorf("encode update-request: %w", err)
111		}
112		body := io.Reader(bytes.NewReader(header.Bytes()))
113		if packData != nil {
114			body = io.MultiReader(body, packData)
115		}
116		reader, err := PostRPCStreamBody(ctx, conn, transport.ReceivePackService, body, false, "receive-pack push")
117		if err != nil {
118			return fmt.Errorf("target receive-pack: %w", err)
119		}
120		defer reader.Close()
121	
122		// Unwrap sideband if negotiated; stream server-side progress to stderr
123		// when verbose so long-running pushes show "Resolving deltas ..." etc.
124		var respReader io.Reader = reader
125		switch {
126		case req.Capabilities.Supports(capability.Sideband64k):
127			dem := sideband.NewDemuxer(sideband.Sideband64k, reader)
128			dem.Progress = progressSink(verbose, "target: ")
129			respReader = dem
130		case req.Capabilities.Supports(capability.Sideband):
131			dem := sideband.NewDemuxer(sideband.Sideband, reader)
132			dem.Progress = progressSink(verbose, "target: ")
133			respReader = dem
134		}
135	
136		if req.Capabilities.Supports(capability.ReportStatus) {
137			report := packp.NewReportStatus()
138			if err := report.Decode(respReader); err != nil {
139				return fmt.Errorf("decode report-status: %w", err)
140			}
141			if err := report.Error(); err != nil {
142				return fmt.Errorf("report-status: %w", err)
143			}
144		}
145		return nil
146	}
