55	// buildUpdateRequest builds the receive-pack update request.
56	func buildUpdateRequest(
57		adv *packp.AdvRefs,
58		commands []PushCommand,
59		verbose bool,
60	) (*packp.UpdateRequests, bool, bool, error) {
61		req := packp.NewUpdateRequests()
62		if sb := PreferredSideband(adv.Capabilities); sb != "" {
63			if err := req.Capabilities.Set(sb); err != nil {
64				return nil, false, false, fmt.Errorf("set capability: %w", err)
65			}
66		}
67		if adv.Capabilities.Supports(capability.ReportStatus) {
68			if err := req.Capabilities.Set(capability.ReportStatus); err != nil {
69				return nil, false, false, fmt.Errorf("set capability: %w", err)
70			}
71		}
72	
73		hasDelete := false
74		hasUpdates := false
75		for _, cmd := range commands {
76			c := &packp.Command{Name: cmd.Name, Old: cmd.Old}
77			if cmd.Delete {
78				c.New = plumbing.ZeroHash
79				hasDelete = true
80			} else {
81				c.New = cmd.New
82				hasUpdates = true
83			}
84			req.Commands = append(req.Commands, c)
85		}
86	
87		if hasDelete {
88			if !adv.Capabilities.Supports(capability.DeleteRefs) {
89				return nil, false, false, errors.New("target does not support delete-refs")
90			}
91			if err := req.Capabilities.Set(capability.DeleteRefs); err != nil {
92				return nil, false, false, fmt.Errorf("set capability: %w", err)
93			}
94		}
95	
96		_ = verbose // progress handling is server-side in HTTP mode
97		return req, hasDelete, hasUpdates, nil
98	}
